49	void apply_repetition_penalties_(
50	    torch::Tensor& logits,             // [num_seqs, vocab_size], in-place
51	    const torch::Tensor& prompt_mask,  // [num_seqs, vocab_size]
52	    const torch::Tensor& output_mask,  // [num_seqs, vocab_size]
53	    const torch::Tensor& repetition_penalties) {  // [num_seqs]
54	  TORCH_CHECK(logits.is_contiguous());
55	  TORCH_CHECK(prompt_mask.is_contiguous());
56	  TORCH_CHECK(output_mask.is_contiguous());
57	  TORCH_CHECK(repetition_penalties.is_contiguous());
58	
59	  int vocab_size = logits.size(-1);
60	  int num_seqs = logits.size(0);
61	
62	  if (num_seqs == 0) return;
63	
64	  // Get number of SMs on the current device
65	  int sms = 0;
66	  cudaDeviceGetAttribute(&sms, cudaDevAttrMultiProcessorCount,
67	                         logits.get_device());
68	
69	  // Compute tile_num and tile_size
70	  int tile_num =
71	      std::min(vocab_size, std::max(1, (sms + num_seqs - 1) / num_seqs));
72	  int tile_size = (vocab_size + tile_num - 1) / tile_num;
73	
74	  // Each block handles one sequence and a tile of vocab
75	  dim3 grid(num_seqs, tile_num);
76	  dim3 block(std::min(tile_size, 1024));
77	  const at::cuda::OptionalCUDAGuard device_guard(device_of(logits));
78	  const cudaStream_t stream = at::cuda::getCurrentCUDAStream();
79	  VLLM_DISPATCH_FLOATING_TYPES(
80	      logits.scalar_type(), "apply_repetition_penalties_kernel", [&] {
81	        vllm::apply_repetition_penalties_kernel<scalar_t>
82	            <<<grid, block, 0, stream>>>(
83	                logits.data_ptr<scalar_t>(), prompt_mask.data_ptr<bool>(),
84	                output_mask.data_ptr<bool>(),
85	                repetition_penalties.data_ptr<scalar_t>(), num_seqs, vocab_size,
86	                tile_size);
87	      });
88	}

